class Solution:
    def floodFill(self, image, sr, sc, color):
        rows = len(image)
        cols = len(image[0])
        start = image[sr][sc]
        if start == color:
            return image
        changed = True
        marked = [[False] * cols for _ in range(rows)]
        marked[sr][sc] = True
        while changed:
            changed = False
            for r in range(rows):
                for c in range(cols):
                    if marked[r][c]:
                        continue
                    if image[r][c] != start:
                        continue
                    for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < rows and 0 <= nc < cols and marked[nr][nc]:
                            marked[r][c] = True
                            changed = True
                            break
        for r in range(rows):
            for c in range(cols):
                if marked[r][c]:
                    image[r][c] = color
        return image

